const express = require('express');
const { Pool } = require('pg');

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432
});

const app = express();
app.use(express.json());

// CRUD for Table1

// Create
app.post('/table1', async (req, res) => {
  const { field1, field2 } = req.body;
  try {
    const result = await pool.query('INSERT INTO table1 (field1, field2) VALUES ($1, $2) RETURNING *', [field1, field2]);
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Read
app.get('/table1/:id', async (req, res) => {
  const { id } = req.params;
  try {
    const result = await pool.query('SELECT * FROM table1 WHERE id = $1', [id]);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Update
app.put('/table1/:id', async (req, res) => {
  const { id } = req.params;
  const { field1, field2 } = req.body;
  try {
    const result = await pool.query('UPDATE table1 SET field1 = $1, field2 = $2 WHERE id = $3 RETURNING *', [field1, field2, id]);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// Delete
app.delete('/table1/:id', async (req, res) => {
  const { id } = req.params;
  try {
    await pool.query('DELETE FROM table1 WHERE id = $1', [id]);
    res.status(204).send();
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

